#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <cstdio>

int main() {
    pid_t pid = fork();

    if (pid < 0) {
        std::cerr << "Failed to fork, you're in big trouble!" << std::endl;
        return 1;
    } else if (pid == 0) {
        // Child process
        std::cout << "Hello, I'm the child process! " << std::endl;
        // Redirect stdin and stdout to the same file descriptor
        dup2(STDOUT_FILENO, STDIN_FILENO);
        std::cout << "I can read from myself now! " << std::endl;
        std::cout << "Type something: ";
        std::string input;
        std::getline(std::cin, input);
        std::cout << "You said: " << input << std::endl;
        // Execute a command
        execlp("ls", "ls", NULL);
        std::cerr << "Failed to exec, better luck next time!" << std::endl;
        return 1;
    } else {
        // Parent process
        std::cout << "Hello, I'm the parent process! " << std::endl;
        wait(NULL); // Wait for the child to finish
    }

    return 0;
}
```

This code will create a child process where the standard input and output are connected to the same file descriptor, allowing the child to read from itself and write back. It's like the child process is chatting with itself!
